def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_ppt = Presentation(original_ppt_path)
        modified_ppt = Presentation(modified_ppt_path)

        # Check if number of slides changed
        if len(original_ppt.slides) != len(modified_ppt.slides):
            return f"Number of slides changed from {len(original_ppt.slides)} to {len(modified_ppt.slides)}", 0.0

        changes_found = []

        # Check each slide except slide 8 (index 7)
        for i, (orig_slide, mod_slide) in enumerate(zip(original_ppt.slides, modified_ppt.slides)):
            if i == 7:  # Skip slide 8
                continue

            # Compare text content
            orig_text = ""
            mod_text = ""

            for shape in orig_slide.shapes:
                if hasattr(shape, "text"):
                    orig_text += shape.text

            for shape in mod_slide.shapes:
                if hasattr(shape, "text"):
                    mod_text += shape.text

            if orig_text != mod_text:
                changes_found.append(f"Slide {i+1} text changed")

        # Check for animation/transition changes on other slides
        other_slide_animations = [anim for anim in ppt_diff.added_animations + [old for old, new in ppt_diff.modified_animations] + ppt_diff.removed_animations if anim.slide_id != "slide_8"]
        other_slide_transitions = [trans for trans in ppt_diff.added_transitions + [old for old, new in ppt_diff.modified_transitions] + ppt_diff.removed_transitions if trans.slide_id != "slide_8"]

        if other_slide_animations:
            changes_found.append(f"Animations changed on other slides: {len(other_slide_animations)} changes")

        if other_slide_transitions:
            changes_found.append(f"Transitions changed on other slides: {len(other_slide_transitions)} changes")

        if changes_found:
            return f"Unintended changes detected: {'; '.join(changes_found)}", 0.3

        return "No unintended changes detected on other slides", 1.0

    except Exception as e:
        return f"Error checking for unintended changes: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Use VLM to check if only the border color changed
    original_slide_8 = None
    modified_slide_8 = None

    for screenshot in original_ppt_screenshots:
        if screenshot.slide_number == 8:
            original_slide_8 = screenshot.image_path
            break

    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 8:
            modified_slide_8 = screenshot.image_path
            break

    if not original_slide_8 or not modified_slide_8:
        raise ScreenshotsUnavailableError("Could not find slide 8 screenshots for comparison; flagging task for verification retry.")

    prompt = """Compare these two PowerPoint slides carefully. The intended change was to add emojis to the slide.

    Analyze if there are any unintended changes:
    1. Has anything other than the emojis changed?

    Respond with:
    - 'MINIMAL_CHANGE' if only the emojis were added as intended
    - 'EXCESSIVE_CHANGE' followed by a description if other unintended modifications were made
    - 'NO_CHANGE' if no changes are visible"""

    try:
        response = vlm_call(prompt, [original_slide_8, modified_slide_8], temperature=0.3)

        response_upper = response.strip()
        if response_upper.startswith('MINIMAL_CHANGE'):
            return "Only the intended emojis were added", 1.0
        elif response_upper.startswith('NO_CHANGE'):
            return "No changes detected on slide 8", 0.0
        else:
            return f"Excessive changes detected: {response}", 0.3
    except Exception as e:
        return f"Error analyzing slide changes: {str(e)}", 0.0
